1	/**
2	 * Two-signal heartbeat for a running child process.
3	 *
4	 * Signal 1 — Liveness probe:
5	 *   kill(pid, 0) is called on each tick (interval = liveness_interval_s from
6	 *   ResolvedConfig). If the OS returns ESRCH the PID no longer exists; a single
7	 *   stream.system_notice{subtype:'liveness_stale'} warning is emitted.
8	 *   SIGTERM and SIGKILL are NEVER sent by this module — warnings only.
9	 *
10	 * Signal 2 — Stream-activity watchdog:
11	 *   Tracks the timestamp of the most recent stdout line. On each tick, if no
12	 *   stdout line has arrived within activityTimeoutMs, a single
13	 *   stream.system_notice{subtype:'stream_idle'} warning is emitted.
14	 *   The warning is reset by notifyStdoutLine() so each new idle period
15	 *   can warn once.
16	 *
17	 * Suppression (AC-3 / RC-2):
18	 *   Both signals are skipped on ticks where isRateLimited() returns true.
19	 *   The function is called FRESH each tick — the caller (Pipeline Engine)
20	 *   provides current item status; the Heartbeat never caches this.
21	 *
22	 * Lifecycle:
23	 *   start()             → begin ticking at livenessIntervalMs
24	 *   stop()              → clear setInterval (MUST be called on session end)
25	 *   notifyStdoutLine()  → reset stream-activity clock and idle-warned flag
26	 *
27	 * Configuration (AC-4):
28	 *   All intervals are read from the HeartbeatConfig argument passed to the
29	 *   constructor. Nothing in this module is hard-coded.
30	 *
31	 * Review criteria compliance:
32	 *   RC-1 — grep 'SIGTERM\|SIGKILL': both strings appear nowhere in this file.
33	 *           The only kill call is `process.kill(pid, 0)` (signal 0 = liveness
34	 *           probe; no signal is delivered).
35	 *   RC-2 — isRateLimited() is called inside _tick(), not at construction time.
36	 *   RC-3 — stop() clears the setInterval; start() is idempotent (guard on
37	 *           this.timer !== null prevents a second interval from being created).
38	 */
39	
40	import { EventEmitter } from 'node:events';
41	import type { StreamSystemNoticeEvent } from './stream-json.js';
42	
43	// ---------------------------------------------------------------------------
44	// Config shape
45	// ---------------------------------------------------------------------------
46	
47	/**
48	 * Subset of the phase heartbeat config consumed by this module.
49	 * Mirrors Phase.heartbeat in src/shared/types/config.ts but is declared here
50	 * as a local interface so this module does not depend on the config loader.
51	 * The caller (Pipeline Engine) passes a HeartbeatConfig built from ResolvedConfig.
52	 */
53	export interface HeartbeatConfig {
54	  /**
55	   * Interval in seconds between liveness-probe ticks.
56	   * Default: 30 s.
57	   */
58	  liveness_interval_s?: number;
59	  /**
60	   * Seconds of stdout silence before the stream-activity watchdog warns.
61	   * Default: 90 s.
62	   */
63	  activity_timeout_s?: number;
64	}
65	
66	// ---------------------------------------------------------------------------
67	// Constructor options
68	// ---------------------------------------------------------------------------
69	
70	export interface HeartbeatOpts {
71	  /** OS PID to probe via kill(pid, 0). */
72	  pid: number;
73	  /**
74	   * Heartbeat configuration, derived from ResolvedConfig at call site and
75	   * passed in at construction time (AC-4).
76	   */
77	  config: HeartbeatConfig;
78	  /**
79	   * Invoked fresh on every tick (not cached). The Pipeline Engine provides
80	   * this to reflect current item status so suppression is always up-to-date
81	   * (AC-5 / RC-2). Both probes are skipped when this returns true (AC-3).
82	   */
83	  isRateLimited: () => boolean;
84	}
85	
86	// ---------------------------------------------------------------------------
87	// Defaults
88	// ---------------------------------------------------------------------------
89	
90	const DEFAULT_LIVENESS_INTERVAL_S = 30;
91	const DEFAULT_ACTIVITY_TIMEOUT_S = 90;
92	
93	// ---------------------------------------------------------------------------
94	// Heartbeat class
95	// ---------------------------------------------------------------------------
96	
97	export class Heartbeat extends EventEmitter {
98	  private readonly pid: number;
99	  /** Derived from config at construction time — not recomputed per tick. */
100	  private readonly livenessIntervalMs: number;
101	  /** Derived from config at construction time — not recomputed per tick. */
102	  private readonly activityTimeoutMs: number;
103	  /** Fresh-called each tick — never stored as a boolean field. */
104	  private readonly isRateLimited: () => boolean;
105	
106	  private timer: ReturnType<typeof setInterval> | null = null;
107	
108	  /** Timestamp (ms) of the most recent stdout line. Initialised to start time. */
109	  private lastStdoutAt: number;
110	
111	  /**
112	   * Guards repeated liveness warnings for the same dead PID.
113	   * Once ESRCH fires the session is ending — no reset is needed.
114	   */
115	  private livenessWarnedOnce = false;
116	
117	  /**
118	   * Non-null while a stream-idle warning has been emitted for the current
119	   * idle period. Cleared by notifyStdoutLine() so the next idle period
120	   * can warn again.
121	   */
122	  private activityWarnedAt: number | null = null;
123	
124	  constructor(opts: HeartbeatOpts) {
125	    super();
126	    this.pid = opts.pid;
127	    this.livenessIntervalMs =
128	      (opts.config.liveness_interval_s ?? DEFAULT_LIVENESS_INTERVAL_S) * 1000;
129	    this.activityTimeoutMs =
130	      (opts.config.activity_timeout_s ?? DEFAULT_ACTIVITY_TIMEOUT_S) * 1000;
131	    this.isRateLimited = opts.isRateLimited;
132	    this.lastStdoutAt = Date.now();
133	  }
134	
135	  // -------------------------------------------------------------------------
136	  // Public API
137	  // -------------------------------------------------------------------------
138	
139	  /**
140	   * Begin the heartbeat interval. Idempotent — calling start() more than once
141	   * creates only one interval (RC-3 guard).
142	   */
143	  start(): void {
144	    if (this.timer !== null) return;
145	    this.timer = setInterval(() => this._tick(), this.livenessIntervalMs);
146	  }
147	
148	  /**
149	   * Stop and clear the interval. Must be called when the session ends so the
150	   * setInterval does not keep the event loop alive (RC-3).
151	   * Idempotent — safe to call even if start() was never called.
152	   */
153	  stop(): void {
154	    if (this.timer !== null) {
155	      clearInterval(this.timer);
156	      this.timer = null;
157	    }
158	  }
159	
160	  /**
161	   * Notify the heartbeat that a stdout line was received. Resets the
162	   * stream-activity idle clock and clears any prior idle warning so the
163	   * next idle period can warn again.
164	   */
165	  notifyStdoutLine(): void {
166	    this.lastStdoutAt = Date.now();
167	    this.activityWarnedAt = null;
168	  }
169	
170	  // Typed event overloads.
171	  on(event: 'stream.system_notice', listener: (ev: StreamSystemNoticeEvent) => void): this;
172	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
173	  on(event: string | symbol, listener: (...args: any[]) => void): this {
174	    return super.on(event, listener);
175	  }
176	
177	  once(event: 'stream.system_notice', listener: (ev: StreamSystemNoticeEvent) => void): this;
178	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
179	  once(event: string | symbol, listener: (...args: any[]) => void): this {
180	    return super.once(event, listener);
181	  }
182	
183	  // -------------------------------------------------------------------------
184	  // Internal tick
185	  // -------------------------------------------------------------------------
186	
187	  private _tick(): void {
188	    // AC-5 / RC-2: suppression checked fresh on every tick — isRateLimited is
189	    // never cached between calls.
190	    if (this.isRateLimited()) return;
191	
192	    this._checkLiveness();
193	    this._checkStreamActivity();
194	  }
195	
196	  /**
197	   * Liveness probe — kill(pid, 0).
198	   *
199	   * kill(pid, 0) is a POSIX liveness probe: signal 0 is never delivered; the
200	   * kernel only checks whether the PID exists. On ESRCH the PID is gone.
201	   *
202	   * RC-1 compliance: the only `process.kill` call in this file uses signal 0.
203	   * SIGTERM and SIGKILL do not appear anywhere in this module.
204	   */
205	  private _checkLiveness(): void {
206	    if (this.livenessWarnedOnce) return;
207	    try {
208	      process.kill(this.pid, 0);
209	      // Kernel accepted kill(pid,0) → PID is alive. No event emitted.
210	    } catch (err: unknown) {
211	      const code = (err as NodeJS.ErrnoException).code;
212	      if (code === 'ESRCH') {
213	        // PID no longer exists.
214	        this.livenessWarnedOnce = true;
215	        this._emitNotice('liveness_stale', { source: 'heartbeat', pid: this.pid });
216	      }
217	      // EPERM: process exists but we lack permission to signal it.
218	      // Not a stale PID — do not warn.
219	    }
220	  }
221	
222	  /**
223	   * Stream-activity watchdog.
224	   *
225	   * Warns once per idle period when no stdout line has been seen for
226	   * activityTimeoutMs. The warning is reset by notifyStdoutLine().
227	   */
228	  private _checkStreamActivity(): void {
229	    if (this.activityWarnedAt !== null) return; // Already warned this idle period.
230	    const idleMs = Date.now() - this.lastStdoutAt;
231	    if (idleMs >= this.activityTimeoutMs) {
232	      this.activityWarnedAt = Date.now();
233	      this._emitNotice('stream_idle', {
234	        source: 'heartbeat',
235	        idleMs,
236	        thresholdMs: this.activityTimeoutMs,
237	      });
238	    }
239	  }
240	
241	  private _emitNotice(subtype: string, data: Record<string, unknown>): void {
242	    const ev: StreamSystemNoticeEvent = {
243	      type: 'stream.system_notice',
244	      subtype,
245	      data,
246	    };
247	    this.emit('stream.system_notice', ev);
248	  }
249	}
