1	/**
2	 * Tests for src/server/process/heartbeat.ts
3	 *
4	 * Acceptance criteria covered:
5	 *   AC-1 — Liveness probe emits stream.system_notice warning on ESRCH; no SIGTERM.
6	 *   AC-2 — Stream-activity watchdog emits warning after configured idle interval.
7	 *   AC-3 — Both probes suppressed while isRateLimited() returns true.
8	 *   AC-4 — Intervals read from config at construction time.
9	 *   AC-5 — Suppression state read fresh each tick, not cached.
10	 *
11	 * Review criteria covered:
12	 *   RC-1 — No SIGTERM / SIGKILL in any probe path — confirmed by mock assertions.
13	 *   RC-2 — Suppression checked per tick, not at construction.
14	 *   RC-3 — stop() clears the interval; no leaked setInterval.
15	 *
16	 * Uses vitest fake timers so all timing is deterministic without wall-clock
17	 * delays. process.kill is spied upon so the liveness probe can be exercised
18	 * without requiring an actual live or dead PID.
19	 */
20	
21	import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
22	import { Heartbeat, type HeartbeatConfig } from '../../src/server/process/heartbeat.js';
23	import type { StreamSystemNoticeEvent } from '../../src/server/process/stream-json.js';
24	
25	// ---------------------------------------------------------------------------
26	// Helpers
27	// ---------------------------------------------------------------------------
28	
29	/** Build a Heartbeat with sensible test defaults. */
30	function makeHeartbeat(
31	  overrides: {
32	    config?: Partial<HeartbeatConfig>;
33	    isRateLimited?: () => boolean;
34	    pid?: number;
35	  } = {},
36	): Heartbeat {
37	  return new Heartbeat({
38	    pid: overrides.pid ?? 12345,
39	    config: {
40	      liveness_interval_s: 10,
41	      activity_timeout_s: 30,
42	      ...overrides.config,
43	    },
44	    isRateLimited: overrides.isRateLimited ?? (() => false),
45	  });
46	}
47	
48	/** Collect all stream.system_notice events emitted by a Heartbeat. */
49	function collectNotices(hb: Heartbeat): StreamSystemNoticeEvent[] {
50	  const events: StreamSystemNoticeEvent[] = [];
51	  hb.on('stream.system_notice', (ev) => events.push(ev));
52	  return events;
53	}
54	
55	// ---------------------------------------------------------------------------
56	// Setup / teardown
57	// ---------------------------------------------------------------------------
58	
59	beforeEach(() => {
60	  vi.useFakeTimers();
61	  // Default: process.kill does nothing (process alive — no throw).
62	  vi.spyOn(process, 'kill').mockReturnValue(true);
63	});
64	
65	afterEach(() => {
66	  vi.restoreAllMocks();
67	  vi.useRealTimers();
68	});
69	
70	// ---------------------------------------------------------------------------
71	// AC-1 — Liveness probe
72	// ---------------------------------------------------------------------------
73	
74	describe('liveness probe', () => {
75	  it('AC-1: emits stream.system_notice with subtype liveness_stale when kill(pid,0) returns ESRCH', () => {
76	    const esrch = Object.assign(new Error('ESRCH'), { code: 'ESRCH' });
77	    vi.spyOn(process, 'kill').mockImplementation(() => {
78	      throw esrch;
79	    });
80	
81	    const hb = makeHeartbeat({ pid: 99999 });
82	    const notices = collectNotices(hb);
83	    hb.start();
84	
85	    vi.advanceTimersByTime(10_000); // one tick at liveness_interval_s=10
86	
87	    expect(notices).toHaveLength(1);
88	    expect(notices[0].type).toBe('stream.system_notice');
89	    expect(notices[0].subtype).toBe('liveness_stale');
90	    expect((notices[0].data as Record<string, unknown>)['source']).toBe('heartbeat');
91	    expect((notices[0].data as Record<string, unknown>)['pid']).toBe(99999);
92	
93	    hb.stop();
94	  });
95	
96	  it('AC-1 / RC-1: does NOT call SIGTERM or SIGKILL — only signal 0 is used', () => {
97	    // If the liveness probe sends any real signal the spy would capture it.
98	    const killSpy = vi.spyOn(process, 'kill').mockReturnValue(true);
99	
100	    const hb = makeHeartbeat();
101	    hb.start();
102	    vi.advanceTimersByTime(10_000);
103	    hb.stop();
104	
105	    // Every kill call must use signal 0 (liveness probe) — never 'SIGTERM' or 'SIGKILL'.
106	    for (const call of killSpy.mock.calls) {
107	      expect(call[1]).toBe(0);
108	    }
109	  });
110	
111	  it('no event emitted when PID is alive (kill(pid,0) does not throw)', () => {
112	    vi.spyOn(process, 'kill').mockReturnValue(true); // no throw = alive
113	
114	    const hb = makeHeartbeat();
115	    const notices = collectNotices(hb);
116	    hb.start();
117	
118	    vi.advanceTimersByTime(10_000);
119	
120	    expect(notices).toHaveLength(0);
121	
122	    hb.stop();
123	  });
124	
125	  it('EPERM does not emit a warning (process alive, permission denied)', () => {
126	    const eperm = Object.assign(new Error('EPERM'), { code: 'EPERM' });
127	    vi.spyOn(process, 'kill').mockImplementation(() => {
128	      throw eperm;
129	    });
130	
131	    const hb = makeHeartbeat();
132	    const notices = collectNotices(hb);
133	    hb.start();
134	
135	    vi.advanceTimersByTime(10_000);
136	
137	    expect(notices).toHaveLength(0);
138	
139	    hb.stop();
140	  });
141	
142	  it('warns exactly once across multiple ticks after ESRCH', () => {
143	    const esrch = Object.assign(new Error('ESRCH'), { code: 'ESRCH' });
144	    vi.spyOn(process, 'kill').mockImplementation(() => {
145	      throw esrch;
146	    });
147	
148	    const hb = makeHeartbeat();
149	    const notices = collectNotices(hb);
150	    hb.start();
151	
152	    // Advance through 5 liveness-probe ticks.
153	    vi.advanceTimersByTime(50_000);
154	
155	    // Only one warning despite 5 ticks — livenessWarnedOnce gate.
156	    expect(notices.filter((n) => n.subtype === 'liveness_stale')).toHaveLength(1);
157	
158	    hb.stop();
159	  });
160	
161	  it('AC-3: liveness probe suppressed when isRateLimited() returns true', () => {
162	    const esrch = Object.assign(new Error('ESRCH'), { code: 'ESRCH' });
163	    vi.spyOn(process, 'kill').mockImplementation(() => {
164	      throw esrch;
165	    });
166	
167	    const hb = makeHeartbeat({ isRateLimited: () => true });
168	    const notices = collectNotices(hb);
169	    hb.start();
170	
171	    vi.advanceTimersByTime(10_000);
172	
173	    expect(notices).toHaveLength(0);
174	
175	    hb.stop();
